+export class ProjectActivityStore {
+	private entries: ProjectActivityRecord[] = [];
+	private readonly jsonl: JsonlStore<unknown>;
+
+	constructor(jsonlPath: string) {
+		this.jsonl = new JsonlStore(jsonlPath);
